/* ImportItemBonus / ImportItemCOST, N.js:17802-17803 (verbatim):
 *   ImportItemBonus(b): row = GamingSprout[25+b]
 *     b==1 (Dirty_Shovel):    floor(10*(1+(60*row[0]/(250+row[0]))^1.7))/10
 *     b==2 (Autumn_Squirrel): round(5*row[0])
 *     b==5 (Bog_Log):         floor(60*row[0]/(100+row[0])*10)/10
 *     else:                   round(row[0])
 *   ImportItemCOST(b) = BoxCost(b)/4 * 1.4^row[0]
 *     where BoxCost(b) = IMPORT_TOOLS[b].costX * 10^IMPORT_TOOLS[b].costY  ("BoxCost"==d case,
 *     N.js:17801, shared with the (separate, non-Gaming) BoxCost lookup on the same table). */
export function importItemCost(b, ownedLevel) {
  const row = IMPORT_TOOLS[b];
  return (row.costX * Math.pow(10, row.costY)) / 4 * Math.pow(1.4, ownedLevel);
}

/** ImportItemBonus(b), N.js:17802 (row = GamingSprout[25+b], field [0] = "owned" stat):
 *   b==1 (Dirty_Shovel):    floor(10*(1 + (60*row0/(250+row0))^1.7))/10
 *   b==2 (Autumn_Squirrel): round(5*row0)
 *   b==5 (Bog_Log):         floor(60*row0/(100+row0)*10)/10
 *   else:                   round(row0)
 * `gamingSprout` is the full save array; this reads row 25+b field [0] itself. */
export function importItemBonus(b, gamingSprout) {
  const row0 = Number(((gamingSprout ?? [])[25 + b] ?? [])[0] ?? 0);
  if (b === 1) return Math.floor(10 * (1 + Math.pow((60 * row0) / (250 + row0), 1.7))) / 10;
  if (b === 2) return Math.round(5 * row0);
  if (b === 5) return Math.floor((60 * row0) / (100 + row0) * 10) / 10;
  return Math.round(row0);
}

