/* "FertilizerUpgCosts"==d, N.js:17762-17763 (verbatim, b indexes the 3 rows above):
 *   b==0 (Sprout Value,  G=Gaming[1]):
 *     (1 + 3*G + G^2) * pow( min(1.25, max(1.13, 1+serverVar("GamingFertCostExpA")/1000))
 *                            + max(0, min(0.15, 0.18*(G-50)/(G+100))) ,  G)
 *   b==1 (Sprout Speed,  G=Gaming[2]):
 *     (2 + 5*G + G^2) * 1.22^G
 *   b==2 (Sprout Capacity, G=Gaming[3]):
 *     if G<11:  (25*(G+1) + (G+1)^3) * (5 + 3.7*G)^G
 *     else:     9999 * 10^(39 + 2*G)
 *   else: 69420 (sentinel, unreachable for b in 0..2)
 * NOTE the server-var-driven exponent floor/ceiling on b==0 only — Sprout Value's cost curve can
 * be tuned live by "GamingFertCostExpA" between 1.13 and 1.25; the other two are fixed constants. */
export function fertilizerUpgCost(b, gaming) {
  if (b === 0) {
    const G = gaming[1];
    const base = Math.min(1.25, Math.max(1.13, 1 + 0 /* serverVar not modeled */ / 1000))
      + Math.max(0, Math.min(0.15, 0.18 * (G - 50) / (G + 100)));
    return (1 + 3 * G + G * G) * Math.pow(base, G);
  }
  if (b === 1) { const G = gaming[2]; return (2 + 5 * G + G * G) * Math.pow(1.22, G); }
  if (b === 2) {
    const G = gaming[3];
    return G < 11
      ? (25 * (G + 1) + Math.pow(G + 1, 3)) * Math.pow(5 + 3.7 * G, G)
      : 9999 * Math.pow(10, 39 + 2 * G);
  }
  return 69420;
}

