// 4. SNAIL ENCOURAGEMENT — "SnailStuff"==d, N.js:17773-17776 (verbatim)
// =============================================================================================
/** Storage: GamingSprout[32] = Immortal Snail's import row (25+7, i=7 in IMPORT_TOOLS).
 *    [1] = snail level (Lv), [2] = "encouragement" stat (mail spent upgrading the snail).
 *  b==0: SUCCESS chance (used as a gate for whatever action the snail's "mail" system rolls):
 *    if Lv>24:  min(1, (1 - 0.6*(Lv-24)^0.16) * (1+Holes("B_UPG",53)/100)
 *                       * (1 + 50*enc/(3+enc)/100))
 *    else:      min(1, (1 - 0.1*Lv^0.71)       * (1+Holes("B_UPG",53)/100)
 *                       * (1 + 110*enc/(25+enc)/100))
 *  b==1: presumably a FAIL/backslide magnitude (mirrors b==0's branch structure, no success cap):
 *    if Lv>24:  max(0, (Lv-24)^0.19 - 0.9) / (1 + 60*enc/(3+enc)/100)
 *    else:      max(0, (Lv+1)^0.07 - 1)    / (1 + 300*enc/(100+enc)/100)
 *  b==2: BITS MULTIPLIER from raw snail level (feeds bits/hr term 11 below, and toolbox's
 *    `snailBonus` — exact match):
 *    2^min(25, max(0,Lv)) * 1.5^min(25, max(0, Lv-25))
 *  b==3: RESET SEMANTICS — third param `e` is caller-supplied (not from GamingSprout), so this
 *    branch is a pure function of its own arguments, not snail state:
 *    if Lv<25 || MaxSnailLV()==25:  round(3 - 2*e)
 *    else:                          round(5 + 25*e)
 *    Call site NOT located in this pass (no `"SnailStuff",3,` grep hit outside the dispatcher
 *    itself) — the caller and hence `e`'s real-world meaning is UNRESOLVED; formula transcribed
 *    verbatim, do not assume a specific interpretation.
 *  else: 0
 *  MaxSnailLV()==d N.js:17806: round(25 + 10*SBT(29) + 5*SBT(30) + 10*SBT(40)) — base cap 25,
 *  +10/+5/+10 from superbits 29 "Snail_Genesis", 30 "Snail_Omega", 40 "Snail_Zenith".
 *  Cross-check: idleon-toolbox's `calculateSnailEncouragementForSuccessChance` (an INVERSE solver
 *  for b==0, gaming.ts:609-622) reproduces the exact same b>24/b<=24 branch split and exponents
 *  (0.6/0.16, 0.1/0.71) — zero formula mismatch on the forward direction re-derived here. */
export function snailStuff(b, snailLv, encouragement, e, holesBUPG53 = 0) {
  if (b === 0) {
    return snailLv > 24
      ? Math.min(1, (1 - 0.6 * Math.pow(snailLv - 24, 0.16)) * (1 + holesBUPG53 / 100) * (1 + 50 * encouragement / (3 + encouragement) / 100))
      : Math.min(1, (1 - 0.1 * Math.pow(snailLv, 0.71)) * (1 + holesBUPG53 / 100) * (1 + 110 * encouragement / (25 + encouragement) / 100));
  }
  if (b === 1) {
    return snailLv > 24
      ? Math.max(0, Math.pow(snailLv - 24, 0.19) - 0.9) / (1 + 60 * encouragement / (3 + encouragement) / 100)
      : Math.max(0, Math.pow(snailLv + 1, 0.07) - 1) / (1 + 300 * encouragement / (100 + encouragement) / 100);
  }
  if (b === 2) {
    return Math.pow(2, Math.min(25, Math.max(0, snailLv))) * Math.pow(1.5, Math.min(25, Math.max(0, snailLv - 25)));
  }
  if (b === 3) {
    const maxSnailLv25 = snailLv < 25; // or MaxSnailLV()==25, not modeled here
    return maxSnailLv25 ? Math.round(3 - 2 * e) : Math.round(5 + 25 * e);
  }
  return 0;
}
export function maxSnailLV(sbt29, sbt30, sbt40) {
  return Math.round(25 + 10 * sbt29 + 5 * sbt30 + 10 * sbt40);
}

