/** Currency = "King Tokens", earned via RatCurrencyGain (only after ResearchStuff("KingRatUnlocked")
 *  is true — a World-7 Research Grid gate). 3 shop upgrade slots, level stored at
 *  GamingSprout[33][b+1] for b in 0..2:
 *    RatShopCost(b)     = 2 * (1.15^lv + lv)                          N.js:17773
 *    RatShopBonuses(b)  = b==0 ? 5*lv : b==1 ? 3*lv : 2*lv             N.js:17773
 *  Call-site-derived labels (no in-game flavour-text table for these 3 rows found in N.js —
 *  idleon-toolbox's gaming.ts:596-598 UI labels "Extra tokens"/"Palette multi"/"Extra crowns"
 *  are the toolbox authors' own descriptive names, not verified N.js strings; kept here only as
 *  a cross-reference, marked unverified):
 *    b=0 -> feeds RatCurrencyGain (King Token gain rate)     [toolbox label: "Extra tokens", UNVERIFIED]
 *    b=1 -> feeds PaletteLuck's RatShopBonuses(1) term        [toolbox label: "Palette multi", UNVERIFIED]
 *    b=2 -> feeds RatCrownOdds                                 [toolbox label: "Extra crowns", UNVERIFIED]
 *
 *  RatCrownOdds(b) [b = number of Crowns already found], N.js:17771-17772:
 *    min(1, 0.05 * (1+0.5*SuperBitType(60)) * (1+SushiStuff("RoG_BonusQTY",31)/100)
 *            * (1 + (RatShopBonuses(2) + GamingSprout[33][0] + ArcadeBonus(65))/100)
 *            * 1.5^b)
 *  RatCurrencyGain(), N.js:17772, gated by `ResearchStuff("KingRatUnlocked")`:
 *    (1+0.5*SuperBitType(50)) * (1 + (PaletteBonus(34) + ResearchStuff("Grid_Bonus",108))/100)
 *      * (1 + Research[11].length/100) * (1+RatShopBonuses(0)/100)
 *    NOTE: PaletteBonus(34) here is colour idx 34 "Maroon_Four", whose own flavour text reads
 *    "}x total Damage for all players" (see gamedata-w5-palette.mjs) — NOT a King-Tokens-themed
 *    colour. Transcribed verbatim from source; flagging as a genuine quirk/cross-system reuse,
 *    not "corrected" to the more intuitive colour 36 "Magenta" ("extra King Tokens per hour",
 *    which is used ELSEWHERE, see bits/hr section) — do not silently swap the index.
 *  RatBitMulti(), N.js:17771 (Research[11].length = Crowns claimed count, used in bits/hr term 15):
 *    max(1, 1.13^crowns + (100*min(10,crowns) + 50*max(0,crowns-10))/100) */
export function ratShopCost(lv) { return 2 * (Math.pow(1.15, lv) + lv); }
export function ratShopBonus(b, lv) { return b === 0 ? 5 * lv : b === 1 ? 3 * lv : 2 * lv; }

