/* NewMutantChanceDEC()==d, N.js:17792-17793 (verbatim, count=Gaming[4], dna=Gaming[5]):
 *   if count==0: min(0.8, 7*dna/(100+dna) * (1+Summoning("VotingBonusz",21)/100))
 *   else: min(0.99, 42*dna/(100+dna) * 0.31^count * (1+Summoning("VotingBonusz",21)/100)
 *              * (1 + 10*max(0, OptionsListAccount[342]/(70*1.7^count + OptionsListAccount[342]))^2))
 *   OptionsListAccount[342] acts as a pity counter fed by FAILED rolls (see roll semantics below).
 *   Cross-check: idleon-toolbox `getNewMutationChance` (gaming.ts:319-324) reproduces the same
 *   0/count branch, 0.8/0.99 caps, and 7 vs 42 coefficients — exact match, zero mismatch.
 *
 * ROLL SEMANTICS (the click-handler around the formula, N.js:16927-16928, verbatim):
 *   on click, if Gaming[5]>0.5 AND Gaming[4]<8:
 *     if random() < NewMutantChanceDEC(): Gaming[4] = min(8, Gaming[4]+1); OptionsListAccount[342] = 0
 *     else: OptionsListAccount[342] += Gaming[5]; Gaming[5] = 0
 *   i.e. SUCCESS unlocks the next mutant type and resets the pity counter to 0; FAILURE banks the
 *   current DNA amount into the pity counter (raising the (10*(pity/...)^2) term for next time)
 *   and zeroes Gaming[5] (the roll "costs" its DNA regardless of outcome). Where Gaming[5] itself
 *   accumulates over time was NOT located in this pass (no direct `Gaming[5]=...+` accrual grep
 *   hit besides this reset/increment pair) — UNRESOLVED, do not assume a rate.
 *
 * MutateUpgCosts()==d, N.js:17778 (spends Bits, levels Gaming[7], separate from the DNA roll):
 *   (25 + 10*(Gaming[7]+1) + (Gaming[7]+1)^2) * 1.3^Gaming[7]
 *   Effect of Gaming[7] on rolls: SproutGrowthCHANCEperMUT()==d, N.js:17794:
 *     0.13 + 0.11*Gaming[7]/(150+Gaming[7])                          (a plant's per-cycle evolve chance) */
export function newMutantChanceDec(count, dna, votingBonusPct = 0) {
  const voteMul = 1 + votingBonusPct / 100;
  if (count === 0) return Math.min(0.8, (7 * dna) / (100 + dna) * voteMul);
  return Math.min(0.99, (42 * dna) / (100 + dna) * Math.pow(0.31, count) * voteMul);
}
export function mutateUpgCost(gaming7) {
  return (25 + 10 * (gaming7 + 1) + Math.pow(gaming7 + 1, 2)) * Math.pow(1.3, gaming7);
}

